                                                    type="text" placeholder="0.00"
                                                    v-on:keypress="NumberTwoDecimal($event, ProductSummary.Adjustments)"
                                                    maxlength="8" v-model="ProductSummary.Adjustments"></td>
                                        </tr>

                                        <tr>
                                            <td colspan="7"
                                                class="text-dark text-right font-weight-bold align-middle border-bottom-0">
                                                {{ $t('Total') }} :</td>
                                            <td colspan="2" class="border-bottom-0"><span
                                                    v-bind:value="summaryTotal">{{ ProductSummary.SummaryTotal }}</span>
                                            </td>
                                        </tr>
                                    </tbody>
                                </table>
                            </div>
                        </div>
                    </div>
                    <div class="row flex-row-reverse mt-2">
                        <div class="col-lg-6 text-right">
                            <a href="javascript:;" v-bind:class="{ disabled: submited }"
                                class="btn btn-warning btnSaveDraft mr-2" v-if="isShowSaveAsDraft"
                                v-on:click="SubmitData('D')" :title="$t('SaveAsDraft')"><em
                                    class="fa fa-save pr-2"></em>{{ $t('SaveAsDraft') }}</a>
                            <a href="javascript:;" v-bind:class="{ disabled: submited }" v-on:click="SubmitData('A')"
                                class="btn btn-success mr-2 addpurchaseorder" title="Save">
                                <em class="fa fa-save pr-2"></em>{{ $t('Save') }}
                            </a>
                            <a href="javascript:void(0)" class="btn btn-danger" title="Cancel" @click="onCancel">
                                <em class="fa fa-close pr-2"></em>{{ $t('Cancel') }}
                            </a>
                        </div>
                        <div class="col-lg-6">
                            <div class="py-2">
                                <small class="text-danger">{{ $t('MandatoryString') }}</small>
                            </div>
                        </div>
                    </div>
                    <modalpricebook v-if="showPricebookModal" :selectedItemIndex="selectedItemIndex"
                        :summaryData="ProductSummary.SummaryData" @close="showPricebookModal = false"
                        @SetPriceBook="SetPriceBook"></modalpricebook>
                </div>
            </div>
        </section>
    </div>
</template>
<script>
import LeadDataService from "../../../services/DataService";
import modalpricebook from '../../../components/Common/Modal/modalpricebook.vue';
var ajaxRequestComplete = true;
export default {
    components: {
        modalpricebook
    },
    data() {
        return {
            FormSchema: [],
            Address: null,
            ProductSummary: null,
            ginStatus: false,
            buttons: [{
                type: "submit",
                class: "btn btn-warning save",
                text: "<i class='fa fa-save pr-2'></i>Save As Draft",
                value: "D",
                isVisible: false,
                onClick: this.saveForm
            },
            {
                type: "submit",
                class: "btn btn-success save",
                isVisible: false,
                text: "<i class='fa fa-save pr-2'></i>Submit",
                onClick: this.saveForm
            },
            {
                type: "button",
                class: "btn btn-danger",
                isVisible: false,
                text: "<i class='fa fa-close pr-2'></i> Cancel",
                onClick: this.Close
            }
            ],
            dateformat: null,
            userId: null,
            companyId: null,
            purchaseorderID: 0,
            Ischeckshipping: this.purchaseorderID > 0,
            AccountId: 0,
            statusId: 0,
            submited: false,
            isTaxNameFilled: false,
            sameShippingAddressAsBilling: false,
            ischeckedshipbox : false,
            ShippingContactPerson: [],
            showPricebookModal: false,
            vSelectValidateSummery: false,
            CountryData: [],
            isShowSaveAsDraft: true
        }
    },
    created: async function () {

        this.userId = this.GetUserInfo.ID;
        this.companyId = this.GetUserInfo.CompanyId;
        this.dateformat = this.GetUserInfo.DateFormat;
        this.purchaseorderID = this.$route.params.id == "0" ? 0 : this.$route.params.id;
        Number.prototype.toFixed2 = function () {
            var amount = Math.floor(parseFloat(this, 10) * 100) / 100;
            return parseFloat(amount, 10).toFixed(2);
        };
        this.FetchData();
        this.GetCountryData('', 'COUNTRIES');
        await this.GetProductFullList();
    },
    computed: {
        summaryTotal: function () {
            let total = 0;
            var data = this.ProductSummary.SummaryData;
            for (let i = 0; i < data.length; i++) {
                if (data[i].ProductRate > 0) {
                    total = parseFloat(total, 10) + parseFloat(data[i].ProductItemTotal, 10);
                }
            }
            total = parseFloat(total, 10).toFixed2();
            this.ProductSummary.SubTotal = total;
            if (this.ProductSummary.ShippingCharges > 0) {
                total = parseFloat(total, 10) + parseFloat(this.ProductSummary.ShippingCharges, 10);
            }
            if (this.ProductSummary.Adjustments > 0) {
                total = parseFloat(total, 10) - parseFloat(this.ProductSummary.Adjustments, 10);
            }
            total = parseFloat(total, 10).toFixed2();
            this.ProductSummary.SummaryTotal = total;
            return total;
        },
    },

    methods: {
        SelectPriceBook: function (item, index) {
            this.selectedItemIndex = index;
            this.showPricebookModal = true;
        },
        onlyDecimal: function (item, type, isInPercentage) {
            var split = item.TAX_RATE.split('.');
            var num2 = "";
            if (split.length > 1) {
                num2 = split[1].substring(0, 2);
                num2 = "." + num2;
            }
            item.TAX_RATE = split[0] + num2;
            if (type == 'TAX') {
                if (item.TAX_NAME != '') {
                    item.TAX_RATE = item.TAX_RATE.replace(/[^0-9.]/g, '').replace(/(\..*)\./g, '$1');
                    if (isInPercentage && parseFloat((item.TAX_RATE != '') ? item.TAX_RATE : 0) > 100) {
                        item.TAX_RATE = '100';
                    }
                } else {
                    this.isTaxNameFilled = true;
                    item.TAX_RATE = "0";
                }
            } else if (type == 'DISCOUNT') {
                item.ProductDiscountValue = item.ProductDiscountValue.replace(/[^0-9.]/g, '').replace(/(\..*)\./g, '$1');
                if (isInPercentage && parseFloat((item.ProductDiscountValue != '') ? item.ProductDiscountValue : 0) > 100) {
                    item.ProductDiscountValue = '100';
                }
            }
        },
        FetchData: function () {
            debugger;
            var vm = this;
            var BillingAddress = {
                BillingContactPerson: '',
                BillingAccountAddress: '',
                BillingAccountAddress2: '',
                BillingAccountCity: '',
                BillingCity: '',
                BillingCityList: [],
                BillingZipCode: '',
                BillingZipCodeList: [],
                BillingState: '',
                BillingStateList: [],
                BillingCountry: '',
            };
            var ShippingAddress = {
                ShippingAccountName: '',
                ShippingContactPerson: '',
                ShippingAccountAddress: '',
                ShippingAccountAddress2: '',
                ShippingAccountCity: '',
                ShippingCity: '',
                ShippingCityList: [],
                ShippingZipCode: '',
                ShippingZipCodeList: [],
                ShippingState: '',
                ShippingStateList: [],
                ShippingCountry: '',
               
            };
            vm.Address = {
                BillingAddress: BillingAddress,
                ShippingAddress: ShippingAddress
            }
            var productSummary = [{
                ProductName: '',
                ProductList: [],
                ProductDescription: '',
                ProductQuantity: 0,
                ProductInStock: 0,
                ProductRate: 0,
                ProductTax: 0,
                ProductAmount: 0,
                ProductDiscount: 0,
                ProductDiscountType: 'percent',
                ProductDiscountValue: 0,
                ProductItemTotal: 0,
                PriceBookId: 0,
                toggleDiscount: false,
                toggleTax: false,
                TaxData: [],
                DiscountData: [],
            }];
            vm.ProductSummary = {
                SubTotal: 0,
                ShippingCharges: 0,
                Adjustments: 0,
                RoundOff: 0,
                SummaryTotal: 0,
                SummaryData: productSummary
            }
            vm.isLoading = true;
            const params = `recordId=${vm.$route.params.id}&moduleName=CRM&subModuleCode=CRM_PURCHASE_ORDERS&langCode=en`;
            LeadDataService.GetDynamicForm(params).then(function (response) {
                debugger
                if (response != null && response.data != null) {
                    vm.isLoading = false;
                    vm.FormSchema = vm.$refs.ManageQuoteForm.ConvertCustomFieldIntoDynamicFormObj(response.data.data);
                    vm.FormSchema.forEach((group, gi) => {
                        group.Data.forEach(async (field, fi) => {
                            if (field.name == "account_id") {
                                if (field.value != null && field.value != "") {
                                    var obj = field.config.options.filter(x => x.value == field.value)[0];
                                    field.value = { label: obj.name, value: obj.value }
                                } else {
                                    field.config.options = [];
                                }
                                field.config.onSearchChange = vm.onSearchh;
                                vm.onSearchh(null, field, " ");
                            }
                            if (field.name == 'gin_status') {
                                if (field.value != null && field.value != '') {
                                    vm.ginStatus = true;
                                }
                            }
                            if (field.name == "contact_id") {
                                if (field.value != null && field.value != "") {
                                    if (field.config.options != undefined) {
                                        var object = field.config.options.filter(x => x.value == field.value)[0];
                                        field.value = { label: object.name, value: object.value }
                                    }
                                    else {
                                        field.config.options = [];
                                    }

                                } else {
                                    field.config.options = [];
                                }
                                field.config.onSearchChange = vm.onSearchh;
                                vm.onSearchh(null, field, " ");
                            }
                            if (field.name == 'order_date' && (field.value == '' || field.value == null)) {
                                field.value = new Date();
                            }
                            if (vm.purchaseorderID > 0) {
                                if (field.name == 'status_id' && (field.value != '' || field.value != null)) {
                                    if (field.value == '1001') {
                                        vm.isShowSaveAsDraft = false
                                    } else {
                                        vm.isShowSaveAsDraft = true;
                                    }
                                }
                            }
                            else {
                                vm.isShowSaveAsDraft = true;
                            }

                            if (field.name == "order_number") {
                                if (vm.purchaseorderID > 0) {
                                    field.value = field.value;
                                }
                                else {
                                    field.value = 'Purchase Order number generated automatically.';
                                }
                                field.disabled = true;
                            }
                            field.config.onChange = vm.onChangeEventForFields;
                        });
                    });
                    if (vm.purchaseorderID > 0) {
                        var addressData = response.data.addressData;
                        var chkBillingAddress = $.grep(addressData, function (element, index) {
                            return element.address_type == 'B';
                        });
                        var billingAddress = null;
                        if (chkBillingAddress.length > 0) {
                            billingAddress = {
                                BillingContactPerson: vm.MakeNormalArray(chkBillingAddress[0].contact_person)[0],
                                BillingAccountAddress: chkBillingAddress[0].account_address,
                                BillingAccountAddress2: chkBillingAddress[0].account_address2,
                                BillingAccountCity: chkBillingAddress[0].city,
                                BillingCity: chkBillingAddress[0].county,
                                BillingCityList: vm.MakeNormalArray(chkBillingAddress[0].county_list),
                                BillingZipCode: chkBillingAddress[0].zip_code,
                                BillingZipCodeList: vm.MakeNormalArray(chkBillingAddress[0].zipcode_list),
                                BillingState: chkBillingAddress[0].state,
                                BillingStateList: vm.MakeNormalArray(chkBillingAddress[0].state_list),
                                BillingCountry: chkBillingAddress[0].country,
                            }
                            vm.ShippingContactPerson = vm.MakeNormalArray(chkBillingAddress[0].contact_person_list);
                        }
                        var chkShippingAddress = $.grep(addressData, function (element, index) {
                            return element.address_type == 'S';
                        });
                        var shippingAddress = null;
                        if (chkShippingAddress.length > 0) {
                            //$("#chkCloneBillingAddress").prop('checked', true).attr('checked', 'checked');
                            shippingAddress = {
                                ShippingContactPerson: chkShippingAddress[0].contact_name,
                                ShippingAccountAddress: chkShippingAddress[0].account_address,
                                ShippingAccountAddress2: chkShippingAddress[0].account_address2,
                                ShippingCity: chkShippingAddress[0].county,
                                ShippingAccountCity: chkShippingAddress[0].city,
                                ShippingCityList: vm.MakeNormalArray(chkShippingAddress[0].county_list),
                                ShippingZipCode: chkShippingAddress[0].zip_code,
                                ShippingZipCodeList: vm.MakeNormalArray(chkShippingAddress[0].zipcode_list),
                                ShippingState: chkShippingAddress[0].state,
                                ShippingStateList: vm.MakeNormalArray(chkShippingAddress[0].state_list),
                                ShippingCountry: chkShippingAddress[0].country
                                
                            }
                            vm.ShippingContactPerson = vm.MakeNormalArray(chkShippingAddress[0].contact_person_list);
                            vm.Ischeckshipping = true;
                            //$("#chkshippingbox").attr("checked", true);
                            vm.ischeckedshipbox = true;
                            if (chkShippingAddress[0].contact_name == "" && chkShippingAddress[0].account_address == "" && chkShippingAddress[0].account_address2 == "" && chkShippingAddress[0].city == "" && (chkShippingAddress[0].zip_code == "" || chkShippingAddress[0].zip_code == 0) && (chkShippingAddress[0].state == "" || chkShippingAddress[0].state == 0) && (chkShippingAddress[0].country == "" || chkShippingAddress[0].country == null)) {
                                vm.Ischeckshipping = false;
                                vm.ischeckedshipbox = false;
                                //$("#chkshippingbox").attr("checked", false);
                            }                           
                        }

                        vm.Address = {
                            BillingAddress: billingAddress,
                            ShippingAddress: shippingAddress
                        }
                        vm.checkForSameBillingAndShippingAddress();

                        var productSummary = [];
                        var productSummaryAmount = response.data.productSummaryAmount;
                        var productSummaryList = response.data.productSummary;
                        $.each(productSummaryList, $.proxy(function (index, item) {
                            var obj = {
                                ProductName: vm.MakeNormalArray(item.product_name)[0],
                                ProductList: vm.MakeNormalArray(item.product_name),
                                ProductDescription: item.item_product_desc,
                                ProductQuantity: item.item_product_Quantity,
                                ProductInStock: 0,
                                ProductRate: item.item_product_list_price,
                                ProductTax: 0,
                                ProductAmount: item.item_product_amount,
                                ProductDiscount: item.item_product_discount,
                                ProductDiscountType: item.item_product_discount_type,
                                ProductDiscountValue: item.item_product_discount_value,
                                ProductItemTotal: item.item_total,
                                PriceBookId: item.item_price_book_id,
                                toggleDiscount: false,
                                toggleTax: false,
                                TaxData: (item.tax_data != null) ? vm.MakeNormalArray(item.tax_data) : [],
                                DiscountData: [],
                            };
                            productSummary.push(obj);
                        }, this));
                        vm.ProductSummary = {
                            SubTotal: productSummaryAmount[0].summary_sub_total,
                            ShippingCharges: productSummaryAmount[0].summary_shipping_charges,
                            Adjustments: productSummaryAmount[0].summary_adjustments,
                            SummaryTotal: productSummaryAmount[0].summary_total,
                            SummaryData: productSummary
                        }

                    } else {
                        vm.GetDropDownData('ACCOUNT_CONTACTS', null, 0, 'BillingContactList');
                    }
                }
            })
        },
        onSearchh: function (e, selctedValue, search) {
            var vm = this;
            vm.searchSelectDataa(search, vm, selctedValue);
        },
        searchSelectDataa: function (search, ths, selctedValue) {
            this.ShowSearchDataa(search, ths, selctedValue);
        },
        CalculateTax: function () {
            var data = this.ProductSummary.SummaryData;
            var vm = this;
            $.each(data, $.proxy(function (key, item) {
                vm.ShowTaxItems(item);
            }, this));
        },
        ShowTax: function (item) {
            item.toggleTax = !item.toggleTax;
        },
        ShowTaxItems: function (item) {
            var state = this.Address.ShippingAddress.ShippingState;
            var countryId = this.Address.ShippingAddress.ShippingCountry;
            var zipcode = this.Address.ShippingAddress.ShippingZipCode;
            var district = this.Address.ShippingAddress.ShippingCity;
            var projectId = 0;
            if (item.ProductName != null) {
                if (Array.isArray(item.ProductName)) {
                    projectId = item.ProductName[0];
                }
                else {
                    projectId = item.ProductName.value;
                }
            }
            item.TaxData = [];
            if (projectId > 0 && countryId > 0) {
                var url = `state=${state}&zipcode=${zipcode}&district=${district}&countryId=${countryId}&projectId=${projectId}`;
                LeadDataService.GetTaxByProduct(url)
                    .then(response => {
                        var json = response.data;
                        if (json != null && json != "") {
                            item.TaxData = json.DATA;
                            return item.TaxData;
                        }
                    });
            }
        },
        ShowSearchDataa: async function (search, ths, selctedValue) {
            var vm = this;
            var appendingUrl = '';
            if (selctedValue.name == 'account_id') {
                appendingUrl = `id=&&moduleName=CRM&type=VENDOR_NAME&search=${search}&refId=`;
            } else if (selctedValue.name == 'contact_id') {
                appendingUrl = `id=&&moduleName=CRM&type=VENDOR_CONTACTS&search=${search}&refId=`;
            }
            selctedValue.config.options = [];
            if (typeof (selctedValue) == 'undefined') {
                selctedValue = 0;
            }
            await LeadDataService.getDDLData(appendingUrl).then(function (response) {
                if (response.data) {
                    vm.JsonObj = response.data;
                    if (vm.JsonObj != null) {
                        response.data.DATA.forEach((item) => {
                            var obj = {
                                value: item.value,
                                name: item.name
                            }
                            selctedValue.config.options.push(obj);
                        })
                        vm.$refs.ManageQuoteForm.UpdateKeyValue();
                    }
                }
            });
        },
        onChangeEventForFields: function (x, y, z) {
            let ths = this;
            if (y.name == "account_id") {
                ths.FormSchema.forEach((group, gi) => {
                    group.Data.forEach(async (field, fi) => {
                        if (field.name == 'contact_id') {
                            let id = z.value;
                            await ths.GetDropDownData('ACCOUNT_CONTACTS', field, id, null);
                        }
                    })
                })
            }
        },
        GetDropDownData: async function (type, field, id, action) {
            
            var vm = this;
            var url = `id=&moduleName=CRM&type=${type}&refId=${id}`;
            if (action == 'BillingContactList') {
                vm.ShippingContactPerson = [];
            } else {
                field.config.options = [];
            }
            await LeadDataService.getDDLData(url + "&search=").then(response => {
                if (response.data.DATA != undefined) {
                    if (action == 'BillingContactList') {
                        vm.ShippingContactPerson = response.data.DATA;
                    } else {
                        var options = response.data.DATA;
                        vm.ShippingContactPerson = response.data.DATA;
                        vm.Address.ShippingAddress.ShippingContactPerson = vm.ShippingContactPerson[0];
                        vm.Address.BillingAddress.BillingContactPerson = vm.ShippingContactPerson[0];
                        options.forEach((item) => {
                            field.config.options.push({
                                value: item.value,
                                name: item.name
                            });
                        });
                        field.value = options[0].value;
                    }
                    vm.$refs.ManageQuoteForm.UpdateKeyValue();
                }
            });
        },
        GetProductFullList: function onSearch() {
            var vm = this;
            vm.ProductSummary.SummaryData.forEach(element => {
                vm.onSearch(" ", element, 'ITEM_NAME_SUMMARY');
            });
        },
        onSearch: function onSearch(search, objItem, isFor) {
            if (search) {
                this.searchSelectData(search, this, objItem, isFor);
            }
        },
        searchSelectData: function (search, vm, objItem, isFor) {
            this.ShowSearchData(search, vm, objItem, isFor);
        },
        ShowSearchData(search, vm, objItem, isFor) {
            var url = "";
            if (isFor == "ITEM_NAME_SUMMARY") {
                url = `id=&moduleName=${this.$route.params.moduleName}&type=ITEM_NAME_PO`;
            }
            else {
                var refId = 0;
                if (vm.AccountId > 0) {
                    refId = vm.AccountId;
                }
                url = `id=&moduleName=${vm.$route.params.moduleName}&type=${objItem.field_code}&refId=${refId}`;
            }
            LeadDataService.getDDLData(url + "&search=" + escape(search))
                .then(response => {
                    var json = [];
                    if (response.data == '') {

                    }
                    if (response.data != '') {
                        json = response.data;
                    }
                    if (isFor == "ITEM_NAME_SUMMARY") {
                        $.each(vm.ProductSummary.SummaryData, function (key, item) {
                            json.DATA = json.DATA.filter(function (el) {
                                return (item.ProductName != null && el.value == item.ProductName.value) ? false : true;
                            });
                        });
                        objItem.ProductList = json.DATA;
                        return objItem.ProductList;
                    }
                    else {
                        objItem.select_options = json.DATA;
                        return objItem.select_options;
                    }
                });
        },
        setSelectedValue(item, val, isFor, type) {
            
            var vm = this;
            if (isFor == 'shipping') {
                var refId = val;
                if (isFor != 'search') {
                    refId = val.value;
                }
                var search = '';
                if (typeof (refId) != "undefined") {
                    var url = `id=&moduleName=${vm.$route.params.moduleName}&type=${type}&refId=${refId}`;
                    LeadDataService.getDDLData(url + "&search=" + escape(search))
                        .then(response => {
                            var json = response.data;
                            if (json != null) {
                                vm.Address.ShippingAddress.ShippingContactPerson = '';
                                return vm.ShippingContactPerson = json.DATA;
                            }
                        });
                }
            }
            else if (isFor == "BillingContactPerson") {
                item.BillingContactPerson = val;
            }
            else if (isFor == "ShippingContactPerson") {
                item.ShippingContactPerson = val;
            }
            else if (isFor == "ITEM_NAME_SUMMARY") {
                item.ProductName = val;
                if (ajaxRequestComplete) {
                    item.ProductInStock = val.first_value;
                    if (val.second_value > 0) {
                        item.ProductRate = val.second_value;
                    }
                    vm.ShowTaxItems(item);
                    vm.CalculateAmount(item);
                    item.PriceBookId = 0;
                }
            }
            else {
                try {
                    var selectedVal = val;
                    if (Array.isArray(val)) {
                        selectedVal = val[0];
                    }

                    if (item.name == 'account_id' && (selectedVal.value > 0 || typeof selectedVal == 'object')) {
                        vm.AccountId = selectedVal.value;
                        vm.FillDropdown('VENDOR_CONTACTS', vm.AccountId);
                    }
                }
                catch (ex) {
                }
            }
        },
        GetCountryData(search, type) {
            
            var vm = this;
            var url = `id=&moduleName=${vm.$route.params.moduleName}&type=${type}`;
            LeadDataService.getDDLData(url + "&search=" + escape(search))
                .then(response => {
                    
                    var json = response.data;

                    if (json != null) {
                        vm.CountryData = json.DATA;
                        var UnitedStateVAl = json.DATA.filter(v => v.name == "United States");
                        var id = vm.purchaseorderID;
                        if (UnitedStateVAl != null && UnitedStateVAl.length > 0 && id == "0") {
                            vm.FillDropdown("BillingState", UnitedStateVAl[0].value)
                            vm.Address.BillingAddress.BillingCountry = UnitedStateVAl[0].value;
                        }
                    }
                });
            url = `id=&moduleName=${vm.$route.params.moduleName}&type=ACCOUNTS`;
            LeadDataService.getDDLData(url + "&search=" + escape(search))
                .then(response => {
                    var json = response.data;

                    if (json != null) {
                        vm.AccountData = json.DATA;
                    }
                });
        },
        CloneBillingAddress: function (event, type) {
            if (typeof (type) != "undefined") {
                if (type != 'loadtax') {
                    this.FillDropdown(type, event.target.value);
                }
                if (type == "ShippingZipCode" || type == "ShippingCity" || type == "ShippingState" || type == 'loadtax') {
                    this.CalculateTax();
                }
            }
            else {
                if ($("#chkCloneBillingAddress").prop("checked")) {
                    this.Address.ShippingAddress.ShippingContactPerson = this.Address.ShippingAddress.BillingContactPerson;
                    this.Address.ShippingAddress.ShippingZipCodeList = this.Address.BillingAddress.BillingZipCodeList;
                    this.Address.ShippingAddress.ShippingCityList = this.Address.BillingAddress.BillingCityList;
                    this.Address.ShippingAddress.ShippingStateList = this.Address.BillingAddress.BillingStateList;
                    this.Address.ShippingAddress.ShippingAccountAddress = this.Address.BillingAddress.BillingAccountAddress;
                    this.Address.ShippingAddress.ShippingAccountAddress2 = this.Address.BillingAddress.BillingAccountAddress2;
