        NumberTwoDecimal: function ($event, PresentVal) {
            let keyCode = ($event.keyCode ? $event.keyCode : $event.which);
            let value = PresentVal.toString();

            if ((keyCode < 48 || keyCode > 57) && (keyCode !== 46 || value.indexOf(".") != -1)) {
