        SetPriceBook: function (item) {
            var index = this.selectedItemIndex;
            this.ProductSummary.SummaryData[index].ProductRate = item.LIST_PRICE;
            this.ProductSummary.SummaryData[index].PriceBookId = item.PRICE_BOOK_ID;
            this.ProductSummary.SummaryData[index].DiscountData = this.MakeNormalArray(item.PRICE_BOOK_RANGE);
            this.ProductSummary.SummaryData[index].ProductDiscountType = ((item.PRICE_BOOK_MODEL == 2) ? 'percent' : 'flat');
            this.showPricebookModal = false;
            this.CalculateAmount(this.ProductSummary.SummaryData[index]);
        },
        CalculateAmount: function (item) {
            if (item.ProductQuantity > 0 && item.ProductRate > 0) {
                item.ProductAmount = parseFloat(item.ProductQuantity, 10) * parseFloat(item.ProductRate, 10);
                this.CalculateDiscount(item);
            }
        },
        CalculateDiscount: function (item) {
            var chkItem = $.grep(item.DiscountData, function (element, index) {
                return element.FROM_RANGE <= item.ProductQuantity && element.TO_RANGE >= item.ProductQuantity;
            });
            if (chkItem != null && chkItem.length > 0) {
                item.ProductDiscountType = 'percent',
                    item.ProductDiscountValue = parseFloat(chkItem[0].DISCOUNT, 10).toFixed2();
            }
        },
        totalSumlineItem: function (item) {
            var productAmount = 0;
            var productDiscount = 0;
            var productTax = 0;
            if (item.ProductAmount > 0) {
                productAmount = parseFloat(item.ProductAmount, 10);
            }
            productAmount = parseFloat(productAmount, 10);
            if (item.ProductDiscountType == 'percent') {
                var discountTypeValue = ($.trim(item.ProductDiscountValue) != '') ? $.trim(item.ProductDiscountValue) : 0;
                if (discountTypeValue > 0) {
                    var c = (parseFloat(productAmount, 10) * parseFloat(discountTypeValue, 10)) / 100;
                    item.ProductDiscount = parseFloat(c, 10).toFixed2();
                }
                else {
                    item.ProductDiscount = 0;
                }
            }
            else {
                item.ProductDiscount = parseFloat((($.trim(item.ProductDiscountValue) != '') ? $.trim(item.ProductDiscountValue) : 0), 10).toFixed2();
            }
            if (item.ProductDiscount > 0) {
                productDiscount = parseFloat(item.ProductDiscount, 10);
                productAmount = parseFloat(productAmount, 10) - parseFloat(item.ProductDiscount, 10);
            }
            if (item.TaxData != null && item.TaxData.length > 0) {
                var totalTax = 0;
                $.each(item.TaxData, $.proxy(function (index, taxItem) {
                    var taxrate = parseFloat(taxItem.TAX_RATE, 10);
                    if (taxItem.TAX_TYPE == "percent") {
                        if (taxrate > 0) {
                            var c = (parseFloat(productAmount, 10) * parseFloat(taxrate, 10)) / 100;
                            totalTax += parseFloat(c, 10);
                        }
                    }
                    else {
                        totalTax += parseFloat(taxrate, 10);
                    }
                }, this));
                if (totalTax > 0) {
                    totalTax = parseFloat(totalTax, 10);
                    productAmount = parseFloat(productAmount, 10) + parseFloat(totalTax, 10);
                    item.ProductTax = totalTax.toFixed2();
                } else {
                    item.ProductTax = 0.00;
                }
            }
            var total = 0;
            total = (parseFloat(item.ProductAmount, 10) + parseFloat(item.ProductTax, 10)) - (parseFloat(item.ProductDiscount, 10)).toFixed2();
            item.ProductItemTotal = parseFloat(total, 10).toFixed2();
            return total.toFixed2();
        },
        DeleteMoreTax: function (item, taxItem) {
            var vm = this;
            vm.confirmR(vm.$t("ConfirmDeleteRecord"), true, (vm.$t("Delete") + "  " + vm.$t("Tax")), function () {
                item.TaxData.splice(taxItem, 1);
                item.ProductTax = '0.00';
