                TAX_FOR: 'custom',
                TAX_TYPE: 'percent',
                TAX_RATE: 0,
                TAX_NAME: ''
            }
            item.TaxData.push(objTax);
        },
        isNumberOnly: function (evt) {
            var charCode = (evt.which) ? evt.which : evt.keyCode;
            if ((charCode > 31 && (charCode < 48 || charCode > 57)) && charCode !== 46) {
                evt.preventDefault();
            } else {
                if (event.which < 48 || event.which > 57) {
                    event.preventDefault();
                } else {
                    if ((charCode > 31 && (charCode < 48 || charCode > 57)) && charCode == 46) {
                        event.preventDefault();
                    }
                    else {
                        return true;
                    }
                }
            }
        },
